.list-item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: 36px;
  padding: 0 $space-3;
  border-radius: $radius-md;
  cursor: pointer;
  transition: background-color $transition-fast ease;

  &:hover:not(&--active) {
    background-color: $color-surface-hover;
  }

  &--active {
    background-color: $color-accent;

    .list-item__title {
      color: $color-text-on-accent;
    }

    .list-item__subtitle {
      color: $color-text-on-accent-secondary;
    }

    .list-item__icon {
      color: $color-text-on-accent;
    }

    .list-item__accessory {
      color: $color-text-on-accent-secondary;
    }

    .list-item__accessory-text {
      color: $color-text-on-accent-secondary;
    }
  }
}

.list-item__left {
  display: flex;
  align-items: center;
  gap: $space-2;
  min-width: 0;
  flex: 1;
