      if (e.metaKey || e.ctrlKey || e.altKey) return;

      if (e.key === 'ArrowDown') {
        e.preventDefault();
        setActiveIndex(activeIndex < itemCount - 1 ? activeIndex + 1 : 0);
      } else if (e.key === 'ArrowUp') {
        e.preventDefault();
        setActiveIndex(activeIndex > 0 ? activeIndex - 1 : itemCount - 1);
      } else if (e.key === 'Enter') {
        e.preventDefault();
        onAction?.(activeIndex);
      }
    }

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [
    activeIndex,
    itemCount,
    setActiveIndex,
    onAction,
  ]);

  const contextValue = useMemo(
    () => ({
      activeIndex,
      setActiveIndex,
    }),
    [
      activeIndex,
      setActiveIndex,
    ],
  );

  return (
    <ListContext value={contextValue}>
      <div
        ref={containerRef}
        className="list"
        role="listbox"
        aria-activedescendant={`list-item-${activeIndex}`}
        tabIndex={0}
      >
        {children}
      </div>
    </ListContext>
  );
}

