.detail-metadata__label {
  color: $color-text-secondary;
  font-size: $font-sm;
  flex-shrink: 0;
  margin-right: $space-3;
}

.detail-metadata__value {
  display: inline-flex;
  align-items: center;
  gap: $space-1;
  color: $color-text-primary;
  font-size: $font-sm;
  text-align: right;
}

.detail-metadata__value-icon {
  display: inline-flex;
  align-items: center;
  width: $space-4;
  height: $space-4;
}

.detail-metadata__link {
  color: $color-accent;
  font-size: $font-sm;
  text-decoration: none;

  &:hover {
    color: $color-accent-hover;
    text-decoration: underline;
  }
}

.detail-metadata__tags {
  display: flex;
  flex-wrap: wrap;
  gap: $space-1;
  justify-content: flex-end;
}

.detail-metadata__tag {
  display: inline-flex;
  align-items: center;
  padding: $space-half $space-2;
